  "process_recipe": [
    {
      "step_index": 1,
      "description": "Dry and pre‑mix monomers (bisphenol‑A, 4,4′‑oxydiphthalic anhydride, and a suitable diamine such as 4,4′‑diaminodiphenylsulfone) under inert atmosphere.",
      "conditions": "Temperature: <50 °C; Pressure: atmospheric; Time: 1 h; Atmosphere: N₂",
      "equipment_class": "sealed glass or stainless steel batch reactor with nitrogen inlet",
      "inputs": ["bisphenol‑A", "4,4′‑oxydiphthalic anhydride", "diamine"]
    },
    {
      "step_index": 2,
      "description": "Heat the mixture to initiate polycondensation while continuously removing water and excess anhydride by azeotropic distillation.",
      "conditions": "Temperature: 240–260 °C; Pressure: reduced (0.1–0.5 bar) or vacuum; Time: 12–18 h; Atmosphere: N₂",
      "equipment_class": "high‑temperature batch reactor with reflux condenser and vacuum line",
      "inputs": ["pre‑mixed monomers"]
    },
    {
      "step_index": 3,
      "description": "Continue polymerization until the desired viscosity (≈10–20 cP at 260 °C) is reached, indicating high molecular weight.",
      "conditions": "Temperature: 260 °C; Pressure: atmospheric; Time: additional 6–8 h",
      "equipment_class": "batch reactor with temperature control and viscometer probe",
      "inputs": ["polymerizing mixture"]
    },
    {
      "step_index": 4,
      "description": "Precipitate the polymer by pouring the hot melt into excess cold methanol, then filter and wash to remove residual monomers.",
      "conditions": "Temperature: 260 °C for melt; Methanol temperature: <5 °C; Time: until solid forms",
      "equipment_class": "filtration unit with vacuum manifold",
      "inputs": ["polymer melt", "methanol"]
    },
    {
      "step_index": 5,
      "description": "Dry the precipitated polymer under vacuum at 80–100 °C for 12 h to remove solvent and achieve final product.",
      "conditions": "Temperature: 80–100 °C; Pressure: <0.01 bar; Time: 12 h",
      "equipment_class": "vacuum oven or rotary evaporator",
      "inputs": ["precipitated polymer"]
    }
  ],
  "evidence": [
    "Polyetherimide (PEI) is routinely synthesized by high‑temperature polycondensation of bisphenol‑A, oxydiphthalic anhydride, and diamines; literature reports lab‑scale batches using sealed reactors.",
    "Typical polymerization temperatures are 240–260 °C with nitrogen purge to prevent oxidation, matching the conditions above.",
    "Removal of water/anhydride by azeotropic distillation or vacuum is standard practice for achieving high molecular weight PEI.",
    "Precipitation in methanol and subsequent vacuum drying are common purification steps for thermoplastics synthesized via polycondensation."
  ]
}
